def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 4):
                    for c in range(1, b + 2):
                        factor = ((ratio - a) ** 7) / ((a * b * c) * 1.1 + 1)
                        priority += factor * np.sin(ratio * b / (c + 1)) * np.cos(ratio * c / (b + 1))
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2
            if bin_cap < item * 0.7:
                priority += np.log1p(item ** 3 * bin_cap) * 7
                for k in range(5, 11):
                    priority -= np.tanh(k * ratio / (item + 1)) * 3
        elif 5 < ratio <= 8:
            s1 = 0
            s2 = 0
            for p in range(1, int(np.ceil(ratio)) + 6):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 0.7)
                    s1 += np.tanh(term) * 1.5
                for r in range(1, q + 1):
                    s2 += np.sin(r * ratio / (p + 0.5)) / (r + 0.6)
            priority = s1 + s2 - np.log(ratio + 0.1) * 12
            if bin_cap > item * 3:
                priority -= np.exp(-2 * ratio) * 5
            elif bin_cap < item * 0.5:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 6
        elif 2 <= ratio <= 5:
            sum_val = 0
            for n in range(1, 15):
                sum_val += ((ratio - 2) ** n) / (n * 2) * np.cos(n * ratio * 1.3)
            priority = sum_val * np.sin(8 * ratio) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
            if i % 2 == 0:
                for m in range(1, 6):
                    priority += np.sin(m * ratio * i) * ((ratio - 1.8) ** m) / (m + 1)
            else:
                for m in range(1, 6):
                    priority -= np.cos(m * ratio * i) * ((ratio - 1.8) ** m) / (m + 1)
        elif 1 <= ratio < 2:
            s = 0
            for x in range(1, 20):
                s += ((2 - ratio) ** x) / (x ** 2 + 1)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for y in range(1, 7):
                priority += np.sin(y * ratio * i) * ((ratio - 0.9) ** y) / (y + 0.3)
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.5
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3) * np.sin(n * item * 0.8)
            priority = s
            if (i + int(item * 1.7)) % 3 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.4
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 2.7)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.4) * 0.6
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 6
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 1.7) % 3 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for t in range(1, 14):
                s += ((0.2 - ratio) ** t) / (t * 5) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 3.5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 9):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.05 - ratio) ** v) / (v * 6) * np.sin(v * item * 1.0)
            priority = s + 4 / (bin_cap + 5)
            if int(item * 0.6) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.05:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for w in range(1, 10):
                priority += ((0.05 - ratio) ** w) / (w * 9) * np.cos(item * w * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * int(item + 1)) % 5 == 0:
            priority += np.tanh(priority / (bin_cap + 1)) * 5
        else:
            priority -= np.tanh(priority / (bin_cap + 1)) * 5
        priorities[i] = priority
    return priorities
